select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b, postgres.users as u where p.id = pl.relatedpostid and b.userid = u.id and c.userid = u.id and p.id = v.postid and p.id = c.postid and p.id = ph.postid and c.score=0 and p.viewcount>=0 and p.answercount<=5 and p.commentcount<=12 and p.favoritecount>=0 and pl.linktypeid=1 and pl.creationdate>=timestamp '2011-02-16 20:04:50' and pl.creationdate<=timestamp '2014-09-01 16:48:04' and v.creationdate>=timestamp '2010-07-19 00:00:00' and v.creationdate<=timestamp '2014-08-31 00:00:00' and b."date">=timestamp '2010-08-06 10:36:45' and b."date"<=timestamp '2014-09-12 07:19:35';
